```go
import (
	"regexp"
	"sort"
)

func contains(s []string, e string) bool {
	for _, v := range s {
		if v == e {
			return true
		}
	}
	return false
}

func solve(code []string, businessLine []string, isActive []bool) []string {
	regex := regexp.MustCompile(`^[a-zA-Z0-9_]+$`)
	allowedBusinessLines := []string{"electronics", "grocery", "pharmacy", "restaurant"}
	businessOrder := map[string]int{
		"electronics": 0,
		"grocery":      1,
		"pharmacy":     2,
		"restaurant":   3,
	}
	validCoupons := make([]struct {
		code string
		businessLine string
	}, 0)

	for i := 0; i < len(code); i++ {
		c := code[i]
		bl := businessLine[i]
		active := isActive[i]

		if c == "" {
			continue
		}
		if !regex.MatchString(c) {
			continue
		}
		if !contains(allowedBusinessLines, bl) {
			continue
		}
		if !active {
			continue
		}
		validCoupons = append(validCoupons, struct {
			code string
			businessLine string
		}{c, bl})
	}

	sort.Slice(validCoupons, func(i, j int) bool {
		orderI := businessOrder[validCoupons[i].businessLine]
		orderJ := businessOrder[validCoupons[j].businessLine]
		if orderI != orderJ {
			return orderI < orderJ
		}
		return validCoupons[i].code < validCoupons[j].code
	})

	result := make([]string, len(validCoupons))
	for i := range validCoupons {
		result[i] = validCoupons[i].code
	}
	return result
}
```

