package main

import (
	"regexp"
	"sort"
)

func solve(code []string, businessLine []string, isActive []bool) []string {
	re := regexp.MustCompile(`^[a-zA-Z0-9_]+$`)
	allowedBusiness := map[string]bool{
		"electronics": true,
		"grocery":      true,
		"pharmacy":     true,
		"restaurant":   true,
	}
	var valid []struct {
		code          string
		businessLine  string
	}
	for i := 0; i < len(code); i++ {
		c := code[i]
		bl := businessLine[i]
		active := isActive[i]
		if c == "" {
			continue
		}
		if !re.MatchString(c) {
			continue
		}
		if !allowedBusiness[bl] {
			continue
		}
		if !active {
			continue
		}
		valid = append(valid, struct {
			code          string
			businessLine  string
		}{c, bl})
	}
	businessOrder := map[string]int{
		"electronics": 0,
		"grocery":      1,
		"pharmacy":     2,
		"restaurant":   3,
	}
	sort.Slice(valid, func(i, j int) bool {
		orderI := businessOrder[valid[i].businessLine]
		orderJ := businessOrder[valid[j].businessLine]
		if orderI != orderJ {
			return orderI < orderJ
		}
		return valid[i].code < valid[j].code
	})
	result := make([]string, len(valid))
	for i, v := range valid {
		result[i] = v.code
	}
	return result
}
```

